import{_ as o,o as t,c as a,ai as c}from"./chunks/framework.CsYGeNYI.js";const m=JSON.parse('{"title":"菜单栏图标","description":"","frontmatter":{"read_when":["更改菜单栏图标行为"],"summary":"macOS 上 OpenSoul 菜单栏图标的状态和动画","title":"菜单栏图标","x-i18n":{"generated_at":"2026-02-01T21:32:49Z","model":"claude-opus-4-5","provider":"pi","source_hash":"a67a6e6bbdc2b611ba365d3be3dd83f9e24025d02366bc35ffcce9f0b121872b","source_path":"platforms/mac/icon.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/icon.md","filePath":"zh-CN/platforms/mac/icon.md","lastUpdated":null}'),r={name:"zh-CN/platforms/mac/icon.md"};function l(i,e,d,s,p,n){return t(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="菜单栏图标状态" tabindex="-1"><a class="header-anchor" href="#菜单栏图标状态">#</a> 菜单栏图标状态</h1><p>作者：steipete · 更新时间：2025-12-06 · 范围：macOS 应用（<code>apps/macos</code>）</p><ul><li><strong>空闲：</strong> 正常图标动画（眨眼、偶尔摆动）。</li><li><strong>暂停：</strong> 状态项使用 <code>appearsDisabled</code>；无动画。</li><li><strong>语音触发（大耳朵）：</strong> 语音唤醒检测器在听到唤醒词时调用 <code>AppState.triggerVoiceEars(ttl: nil)</code>，在捕获语音期间保持 <code>earBoostActive=true</code>。耳朵放大（1.9 倍），显示圆形耳孔以提高可读性，然后在 1 秒静音后通过 <code>stopVoiceEars()</code> 恢复。仅由应用内语音管道触发。</li><li><strong>工作中（智能体运行中）：</strong> <code>AppState.isWorking=true</code> 驱动&quot;尾巴/腿部快速摆动&quot;微动画：工作进行中腿部摆动加快并略有偏移。目前在 WebChat 智能体运行时切换；在接入其他长时间任务时请添加相同的切换逻辑。</li></ul><p>接入点</p><ul><li>语音唤醒：运行时/测试器在触发时调用 <code>AppState.triggerVoiceEars(ttl: nil)</code>，在 1 秒静音后调用 <code>stopVoiceEars()</code> 以匹配捕获窗口。</li><li>智能体活动：在工作区间前后设置 <code>AppStateStore.shared.setWorking(true/false)</code>（已在 WebChat 智能体调用中完成）。保持区间简短，并在 <code>defer</code> 块中重置以避免动画卡住。</li></ul><p>形状与尺寸</p><ul><li>基础图标在 <code>CritterIconRenderer.makeIcon(blink:legWiggle:earWiggle:earScale:earHoles:)</code> 中绘制。</li><li>耳朵缩放默认为 <code>1.0</code>；语音增强时设置 <code>earScale=1.9</code> 并切换 <code>earHoles=true</code>，不改变整体框架（18×18 pt 模板图像渲染到 36×36 px Retina 后备存储）。</li><li>快速摆动使用最高约 1.0 的腿部摆幅并带有轻微的水平抖动；它与现有的空闲摆动叠加。</li></ul><p>行为说明</p><ul><li>耳朵/工作状态没有外部 CLI/代理切换；保持仅由应用自身信号控制，以避免意外的状态抖动。</li><li>保持 TTL 较短（&lt;10 秒），以便在任务挂起时图标能快速恢复到基准状态。</li></ul>',9)])])}const _=o(r,[["render",l]]);export{m as __pageData,_ as default};
